# SAML Configuration
SAML_CONFIG = {
    'sp_entity_id': 'http://localhost:5000/saml/metadata',
    'acs_url': 'http://localhost:5000/saml/acs',
    'idp_sso_url': 'http://idp.example.com/saml/sso',
    'idp_entity_id': 'http://idp.example.com/saml/metadata'
}

# SAML namespaces
NAMESPACES = {
    'samlp': 'urn:oasis:names:tc:SAML:2.0:protocol',
    'saml': 'urn:oasis:names:tc:SAML:2.0:assertion',
    'ds': 'http://www.w3.org/2000/09/xmldsig#'
}

# In-memory storage for SAML requests (in production, use Redis or database)
saml_requests = {}


def generate_saml_request():
    """Generate a SAML AuthnRequest"""
    request_id = f"_{secrets.token_hex(16)}"
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    
    saml_request = f'''<?xml version="1.0" encoding="UTF-8"?>
<samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
                    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
                    ID="{request_id}"
                    Version="2.0"
                    IssueInstant="{issue_instant}"
                    Destination="{SAML_CONFIG['idp_sso_url']}"
                    AssertionConsumerServiceURL="{SAML_CONFIG['acs_url']}"
                    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{SAML_CONFIG['sp_entity_id']}</saml:Issuer>
    <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
                        AllowCreate="true"/>
</samlp:AuthnRequest>'''
    
    # Store request ID for validation
    saml_requests[request_id] = {
        'timestamp': datetime.utcnow(),
        'relay_state': request.args.get('RelayState', '/')
    }
    
    # Encode SAML request
    compressed = zlib.compress(saml_request.encode('utf-8'))[2:-4]
    encoded = base64.b64encode(compressed).decode('utf-8')
    
    return request_id, encoded


def parse_saml_response(saml_response_b64):
    """Parse SAML response and extract assertion data"""
    try:
        # Decode base64 SAML response
        saml_response_xml = base64.b64decode(saml_response_b64)
        root = ET.fromstring(saml_response_xml)
        
        # Parse the response
        response_data = {
            'valid': False,
            'errors': [],
            'attributes': {},
            'nameid': None,
            'session_index': None
        }
        
        # Check if response is successful
        status = root.find('.//samlp:Status/samlp:StatusCode', NAMESPACES)
        if status is None:
            response_data['errors'].append('No status code found in SAML response')
            return response_data
        
        status_value = status.get('Value')
        if status_value != 'urn:oasis:names:tc:SAML:2.0:status:Success':
            response_data['errors'].append(f'SAML response status is not success: {status_value}')
            return response_data
        
        # Find assertions
        assertions = root.findall('.//saml:Assertion', NAMESPACES)
        if not assertions:
            response_data['errors'].append('No assertions found in SAML response')
            return response_data
        
        # Process first assertion
        assertion = assertions[0]
        
        # Extract Subject NameID
        nameid_element = assertion.find('.//saml:Subject/saml:NameID', NAMESPACES)
        if nameid_element is not None:
            response_data['nameid'] = nameid_element.text
        
        # Extract SessionIndex from AuthnStatement
        authn_statement = assertion.find('.//saml:AuthnStatement', NAMESPACES)
        if authn_statement is not None:
            response_data['session_index'] = authn_statement.get('SessionIndex')
        
        # Extract attributes
        attribute_statements = assertion.findall('.//saml:AttributeStatement/saml:Attribute', NAMESPACES)
        for attr in attribute_statements:
            attr_name = attr.get('Name')
            attr_values = []
            
            for value in attr.findall('saml:AttributeValue', NAMESPACES):
                if value.text:
                    attr_values.append(value.text)
            
            if attr_values:
                response_data['attributes'][attr_name] = attr_values[0] if len(attr_values) == 1 else attr_values
        
        # Validate conditions
        conditions = assertion.find('.//saml:Conditions', NAMESPACES)
        if conditions is not None:
            not_before = conditions.get('NotBefore')
            not_on_or_after = conditions.get('NotOnOrAfter')
            
            if not_before and not_on_or_after:
                now = datetime.utcnow()
                not_before_dt = datetime.strptime(not_before, '%Y-%m-%dT%H:%M:%SZ')
                not_on_or_after_dt = datetime.strptime(not_on_or_after, '%Y-%m-%dT%H:%M:%SZ')
                
                if now < not_before_dt:
                    response_data['errors'].append('Assertion not yet valid')
                    return response_data
                
                if now >= not_on_or_after_dt:
                    response_data['errors'].append('Assertion has expired')
                    return response_data
        
        # Validate audience
        audience = assertion.find('.//saml:Conditions/saml:AudienceRestriction/saml:Audience', NAMESPACES)
        if audience is not None:
            if audience.text != SAML_CONFIG['sp_entity_id']:
                response_data['errors'].append(f'Audience mismatch: expected {SAML_CONFIG["sp_entity_id"]}, got {audience.text}')
                return response_data
        
        # Extract InResponseTo
        in_response_to = root.get('InResponseTo')
        if in_response_to:
            if in_response_to not in saml_requests:
                response_data['errors'].append('Invalid InResponseTo value - request not found')
                return response_data
            
            # Clean up old requests
            del saml_requests[in_response_to]
        
        response_data['valid'] = True
        return response_data
        
    except ET.ParseError as e:
        return {
            'valid': False,
            'errors': [f'XML parsing error: {str(e)}'],
            'attributes': {},
            'nameid': None,
            'session_index': None
        }
    except Exception as e:
        return {
            'valid': False,
            'errors': [f'Error processing SAML response: {str(e)}'],
            'attributes': {},
            'nameid': None,
            'session_index': None
        }


@app.route('/')
def index():
    """Home page - shows user session if authenticated"""
    if 'saml_attributes' in session:
        return jsonify({
            'authenticated': True,
            'user': session.get('saml_nameid'),
            'attributes': session.get('saml_attributes'),
            'session_index': session.get('saml_session_index')
        })
    else:
        return jsonify({
            'authenticated': False,
            'message': 'Not authenticated. Please login via /saml/login'
        })


@app.route('/saml/login')
def saml_login():
    """Initiate SAML authentication"""
    request_id, encoded_request = generate_saml_request()
    
    # Redirect to IdP with SAML request
    idp_url = f"{SAML_CONFIG['idp_sso_url']}?SAMLRequest={encoded_request}"
    relay_state = request.args.get('RelayState', '/')
    if relay_state:
        idp_url += f"&RelayState={relay_state}"
    
    return redirect(idp_url)


@app.route('/saml/acs', methods=['POST'])
def assertion_consumer_service():
    """Assertion Consumer Service - processes SAML responses from IdP"""
    saml_response = request.form.get('SAMLResponse')
    relay_state = request.form.get('RelayState', '/')
    
    if not saml_response:
        return jsonify({'error': 'No SAML response received'}), 400
    
    # Parse and validate SAML response
    response_data = parse_saml_response(saml_response)
    
    if not response_data['valid']:
        return jsonify({
            'error': 'SAML response validation failed',
            'details': response_data['errors']
        }), 400
    
    # Create user session
    session.permanent = True
    session['authenticated'] = True
    session['saml_nameid'] = response_data['nameid']
    session['saml_attributes'] = response_data['attributes']
    session['saml_session_index'] = response_data['session_index']
    session['login_time'] = datetime.utcnow().isoformat()
    
    # Redirect to relay state or home
    return redirect(relay_state if relay_state else '/')


@app.route('/saml/logout')
def saml_logout():
    """Logout - clear session"""
    session.clear()
    return jsonify({'message': 'Logged out successfully'})


